import React, { useState } from 'react';

const App = () => {
  const [drafts, setDrafts] = useState([
    { id: 1, title: 'Post 1' },
    { id: 2, title: 'Post 2' },
    { id: 3, title: 'Post 3' }
  ]);
  const [searchTerm, setSearchTerm] = useState('');
  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white p-4 rounded-md shadow-md">
        <h2 className="text-lg font-bold mb-4">Drafts</h2>
        <input type="search" className="bg-gray-100 text-gray-500 rounded-md shadow-md p-2 mb-4" placeholder="Search" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)}/>
        <button className="bg-[#C06C88] text-white rounded-md shadow-md p-2 mb-4">Add</button>
        <ul>
          {drafts.filter((draft) => draft.title.toLowerCase().includes(searchTerm.toLowerCase())).map((draft) => (
            <li key={draft.id} className="bg-white rounded-md shadow-md p-4 mb-4">
              <h3 className="text-lg font-bold mb-2">{draft.title}</h3>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
};\n\nexport default App;
